import{_ as s,c as t,o as a,ag as i}from"./chunks/framework.IQH0tUiJ.js";const g=JSON.parse('{"title":"How It Works","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts/how-it-works.md","filePath":"guide/concepts/how-it-works.md"}'),n={name:"guide/concepts/how-it-works.md"};function r(o,e,l,h,d,p){return a(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h1><p>WebUI is a <strong>language-agnostic server-side rendering framework</strong> that splits template processing into three distinct phases: build, server render, and client hydration. Each phase is optimized for its role, eliminating redundant work and keeping runtime overhead to a minimum.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Build Time              Server Render             Client Hydration</span></span>
<span class="line"><span>──────────────────      ──────────────────        ──────────────────</span></span>
<span class="line"><span>HTML + CSS + TS    →    Protocol + JSON      →    Web Components</span></span>
<span class="line"><span>webui build             state → HTML              hydrate as islands</span></span></code></pre></div><h2 id="build-phase" tabindex="-1">Build Phase <a class="header-anchor" href="#build-phase" aria-label="Permalink to &quot;Build Phase&quot;">​</a></h2><p>The <code>webui build</code> CLI command transforms your template source files into an optimized binary format. This is a one-time cost - the output is reused for every request.</p><p>During the build, WebUI:</p><ol><li><strong>Parses HTML templates</strong> - scans component directories for <code>.html</code>, <code>.css</code>, and <code>.ts</code> files</li><li><strong>Discovers web components</strong> - identifies custom elements by their hyphenated tag names</li><li><strong>Compiles expressions</strong> - resolves <code>{{bindings}}</code>, <code>&lt;if&gt;</code> conditions, <code>&lt;for&gt;</code> loops, and attribute directives into indexed slots</li><li><strong>Separates static from dynamic content</strong> - static HTML becomes pre-serialized byte fragments; dynamic content becomes keyed slots that map to state values</li><li><strong>Emits output artifacts</strong>: <ul><li><code>protocol.bin</code> - binary Protocol Buffer containing the compiled template structure</li><li>CSS files - scoped styles for each component</li><li>JS bundles - client-side Web Component classes for hydration</li></ul></li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">webui</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./src</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --out</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./dist</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --plugin=webui</span></span></code></pre></div><p>The binary protocol is the key to WebUI&#39;s performance. By moving parsing, expression compilation, and template analysis to build time, the server never repeats this work.</p><h2 id="server-render-phase" tabindex="-1">Server Render Phase <a class="header-anchor" href="#server-render-phase" aria-label="Permalink to &quot;Server Render Phase&quot;">​</a></h2><p>At runtime, the server handler loads the compiled protocol <strong>once</strong> at startup and reuses it for every request.</p><p>For each incoming request, the handler:</p><ol><li>Receives a <strong>JSON state object</strong> containing the data for that page</li><li>Walks the compiled protocol fragments in order</li><li>Copies <strong>static fragments</strong> directly to the output buffer (no processing needed)</li><li>Resolves <strong>dynamic fragments</strong> by looking up keys in the JSON state</li><li>Emits the final HTML response</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────┐     ┌────────────────┐     ┌──────────────┐</span></span>
<span class="line"><span>│ protocol.bin │ ──→ │    Handler     │ ──→ │  HTML output  │</span></span>
<span class="line"><span>└──────────────┘     │  + JSON state  │     └──────────────┘</span></span>
<span class="line"><span>                     └────────────────┘</span></span></code></pre></div><h3 id="what-the-handler-does-not-do" tabindex="-1">What the handler does NOT do <a class="header-anchor" href="#what-the-handler-does-not-do" aria-label="Permalink to &quot;What the handler does NOT do&quot;">​</a></h3><ul><li><strong>No template parsing</strong> - already done at build time</li><li><strong>No AST walking</strong> - the protocol is a flat list of fragments</li><li><strong>No expression compilation</strong> - expressions are pre-compiled to key lookups</li><li><strong>No JavaScript runtime</strong> - the server is pure native code (Rust, C, or any FFI host)</li></ul><h3 id="declarative-shadow-dom" tabindex="-1">Declarative Shadow DOM <a class="header-anchor" href="#declarative-shadow-dom" aria-label="Permalink to &quot;Declarative Shadow DOM&quot;">​</a></h3><p>The rendered HTML includes <a href="https://developer.chrome.com/docs/css-ui/declarative-shadow-dom" target="_blank" rel="noreferrer">Declarative Shadow DOM</a> markup. This means the browser can display fully styled component content <strong>before any JavaScript loads</strong>:</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">my-card</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">template</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> shadowrootmode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;open&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">style</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* scoped styles */</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">style</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">h2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Card Title&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">h2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Content rendered on the server&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">template</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">my-card</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>The user sees rendered content immediately - no blank page, no loading spinner.</p><h2 id="client-hydration-phase" tabindex="-1">Client Hydration Phase <a class="header-anchor" href="#client-hydration-phase" aria-label="Permalink to &quot;Client Hydration Phase&quot;">​</a></h2><p>After the browser renders the server HTML, JavaScript loads and Web Components <strong>hydrate</strong> as independent islands of interactivity.</p><h3 id="how-hydration-works" tabindex="-1">How hydration works <a class="header-anchor" href="#how-hydration-works" aria-label="Permalink to &quot;How hydration works&quot;">​</a></h3><ol><li><strong>Custom elements upgrade</strong> - the browser calls <code>connectedCallback</code> for each registered Web Component</li><li><strong>Shadow root detection</strong> - the framework finds the existing Declarative Shadow DOM root (it does <strong>not</strong> recreate the DOM)</li><li><strong>Bindings wired</strong> - template expressions (<code>{{count}}</code>, <code>?disabled</code>) are connected to class properties</li><li><strong>Events connected</strong> - <code>@click</code>, <code>@keydown</code>, and other event handlers are attached</li><li><strong>Reactive state activated</strong> - <code>@observable</code> properties become live; changes trigger targeted DOM updates</li></ol><h3 id="islands-architecture" tabindex="-1">Islands Architecture <a class="header-anchor" href="#islands-architecture" aria-label="Permalink to &quot;Islands Architecture&quot;">​</a></h3><p>Each Web Component is a <strong>self-contained island</strong>. Components hydrate independently - a <code>&lt;search-bar&gt;</code> can be interactive while a <code>&lt;footer-links&gt;</code> component stays as static server-rendered HTML.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                  Page                        │</span></span>
<span class="line"><span>│                                              │</span></span>
<span class="line"><span>│  ┌──────────────┐   ┌────────────────────┐  │</span></span>
<span class="line"><span>│  │  search-bar  │   │   product-grid     │  │</span></span>
<span class="line"><span>│  │  (hydrated)  │   │   (hydrated)       │  │</span></span>
<span class="line"><span>│  └──────────────┘   └────────────────────┘  │</span></span>
<span class="line"><span>│                                              │</span></span>
<span class="line"><span>│  ┌──────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │          footer-links                 │   │</span></span>
<span class="line"><span>│  │          (static - no JS)             │   │</span></span>
<span class="line"><span>│  └──────────────────────────────────────┘   │</span></span>
<span class="line"><span>│                                              │</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span></code></pre></div><p>Only components that need interactivity ship JavaScript. Static content stays as plain HTML with zero JS cost.</p><h2 id="the-ssr-mental-model" tabindex="-1">The SSR Mental Model <a class="header-anchor" href="#the-ssr-mental-model" aria-label="Permalink to &quot;The SSR Mental Model&quot;">​</a></h2><p>Understanding the relationship between server and client is critical for building correct WebUI applications.</p><h3 id="the-server-is-the-source-of-truth-for-the-initial-render" tabindex="-1">The server is the source of truth for the initial render <a class="header-anchor" href="#the-server-is-the-source-of-truth-for-the-initial-render" aria-label="Permalink to &quot;The server is the source of truth for the initial render&quot;">​</a></h3><p>Every value bound in a template - <code>{{expression}}</code>, <code>&lt;for each=&quot;item in items&quot;&gt;</code>, <code>&lt;if condition=&quot;expr&quot;&gt;</code> - must have a corresponding key in the server state JSON. The handler resolves bindings by looking up keys in this JSON object. If a key is missing, the binding renders empty or the condition evaluates to false.</p><h3 id="derived-state-belongs-in-the-server-or-the-template" tabindex="-1">Derived state belongs in the server or the template <a class="header-anchor" href="#derived-state-belongs-in-the-server-or-the-template" aria-label="Permalink to &quot;Derived state belongs in the server or the template&quot;">​</a></h3><p>If a value must appear in the initial HTML, it must come from the server state JSON. Use template expressions for simple derivations:</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&lt;!-- Template expressions work on both server and client --&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">span</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;{{firstName}} {{lastName}}&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">span</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">if</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> condition</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;items.length&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;{{items.length}} items&lt;/</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>For complex derived values, compute them on the server and include them in the state JSON.</p><h3 id="the-client-handles-interactivity-after-hydration" tabindex="-1">The client handles interactivity after hydration <a class="header-anchor" href="#the-client-handles-interactivity-after-hydration" aria-label="Permalink to &quot;The client handles interactivity after hydration&quot;">​</a></h3><p>Once components hydrate, user interactions are handled entirely on the client. Sorting a list, filtering results, toggling a panel - these operations mutate <code>@observable</code> properties directly, and the framework updates the DOM reactively.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Server: &quot;Here&#39;s the initial HTML with all the data.&quot;</span></span>
<span class="line"><span>Client: &quot;Got it. I&#39;ll hydrate the interactive parts and take over from here.&quot;</span></span></code></pre></div><h2 id="what-makes-this-fast" tabindex="-1">What Makes This Fast <a class="header-anchor" href="#what-makes-this-fast" aria-label="Permalink to &quot;What Makes This Fast&quot;">​</a></h2><p>WebUI&#39;s architecture is designed so that the most common operation - rendering a page - does the least possible work.</p><table tabindex="0"><thead><tr><th>Technique</th><th>Impact</th></tr></thead><tbody><tr><td><strong>Pre-serialized static fragments</strong></td><td>Copied byte-for-byte to the output buffer - no processing</td></tr><tr><td><strong>Key-based dynamic resolution</strong></td><td>Simple hash map lookup against JSON state - no expression parsing</td></tr><tr><td><strong>No runtime allocations for structure</strong></td><td>Template shape is fixed at build time; only data values vary</td></tr><tr><td><strong>No JavaScript on the server</strong></td><td>Native code (Rust/C) handles rendering - no VM startup, no GC pauses</td></tr><tr><td><strong>Declarative Shadow DOM</strong></td><td>Browser renders content before JS loads - no white flash</td></tr><tr><td><strong>Islands Architecture</strong></td><td>Only interactive components ship JS - static content has zero client cost</td></tr><tr><td><strong>Binary Protocol Buffer</strong></td><td>Compact, zero-copy deserialization - faster than JSON or text templates</td></tr></tbody></table><p>The result: server render times measured in microseconds, not milliseconds. First Contentful Paint that doesn&#39;t depend on JavaScript. And client-side interactivity that activates without rebuilding the DOM.</p>`,43)])])}const k=s(n,[["render",r]]);export{g as __pageData,k as default};
